/* --- ASTRAL GLASSMORPHISM --- */
* {
	border-color: rgba(100, 150, 255, 0.15) !important;
}

/* Ethereal Typography */
.prose h1, .prose h2, .prose h3, .prose h4 {
	color: #aaddff !important;
	text-shadow: 0 0 15px rgba(136, 187, 255, 0.2);
}
.prose code {
	color: #cdd3f5 !important;
	background-color: rgba(136, 187, 255, 0.1) !important;
	border: 1px solid rgba(136, 187, 255, 0.2);
	border-radius: 6px;
}

/* Frosted Glass Inputs */
input, textarea, .bg-gray-850 {
	background-color: rgba(10, 11, 20, 0.5) !important;
	backdrop-filter: blur(12px) !important;
	-webkit-backdrop-filter: blur(12px) !important;
	border: 1px solid rgba(136, 187, 255, 0.2) !important;
	border-radius: 12px !important;
	box-shadow: inset 0 0 10px rgba(0, 0, 0, 0.5);
	transition: all 0.3s ease;
}
input:focus, textarea:focus {
	border-color: #88bbff !important;
	background-color: rgba(16, 18, 35, 0.7) !important;
	box-shadow: 0 0 20px rgba(136, 187, 255, 0.2), inset 0 0 10px rgba(0, 0, 0, 0.5) !important;
}

/* Starship Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: linear-gradient(135deg, #4488ff, #8855ff) !important;
	border: none !important;
	color: #ffffff !important;
	font-weight: 600 !important;
	border-radius: 20px !important;
	box-shadow: 0 4px 15px rgba(68, 136, 255, 0.3);
	transition: transform 0.2s cubic-bezier(0.4, 0, 0.2, 1), box-shadow 0.2s;
}
button.bg-blue-500:hover, button.bg-blue-600:hover, .bg-black:hover {
	transform: translateY(-3px) scale(1.02);
	box-shadow: 0 8px 25px rgba(136, 85, 255, 0.5) !important;
}

/* Liquid Scrollbar */
::-webkit-scrollbar-thumb {
	background: linear-gradient(to bottom, #4488ff, #8855ff) !important;
	border-radius: 10px;
}
::-webkit-scrollbar-track {
	background: rgba(5, 5, 10, 0.5) !important;
}

/* Animated gradient — Aurora Borealis */
body {
  background-image: linear-gradient(135deg, #0a0a2e, #1a3a5c, #0d7377, #1a3a5c, #0a0a2e) !important;
  background-attachment: fixed !important;
  background-size: 400% 400% !important;
  animation: auroraShift 16s ease infinite !important;
}
@keyframes auroraShift {
  0%   { background-position: 0% 50%; }
  50%  { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

/* Make layout containers transparent */
#app, #app > div, #app > div > div, main, .app,
.bg-gray-900, .bg-gray-950,
.dark\:bg-gray-900, .dark\:bg-gray-950 {
  background-color: transparent !important;
  background-image: none !important;
}

/* Blend chat/folder background images with gradient */
#chat-container .bg-linear-to-t {
  background-image: linear-gradient(
    to top, rgba(10, 10, 46, 0.7), rgba(13, 115, 119, 0.35)
  ) !important;
}

/* Sidebar & input readability */
#sidebar {
  background-color: rgba(10, 10, 46, 0.7) !important;
  backdrop-filter: blur(12px) !important;
}
textarea {
  background-color: rgba(10, 10, 46, 0.5) !important;
  backdrop-filter: blur(8px) !important;

/* Green-line grid */ body {
	background-image: linear-gradient(rgba(26, 255, 26, 0.05) 1px, transparent 1px), linear-gradient(90deg, rgba(26, 255, 26, 0.05) 1px, transparent 1px) !important;
	background-size: 20px 20px !important;
	background-position: center top !important;
	font-family: 'JetBrains Mono', 'Monaco', monospace !important;
}
/* Phosphor borders */ * {
	border-color: rgba(26, 255, 26, 0.25) !important;
}
input, textarea, .prose {
	background-color: rgba(10, 26, 10, 0.85) !important;
	border: 1px solid rgba(26, 255, 26, 0.35) !important;
}
/* Green accent buttons */ button.bg-blue-500, button.bg-blue-600 {
	background-color: #1aff1a !important;
	border: 1px solid #eaffea !important;
	color: #020402 !important;
	text-transform: uppercase;
	letter-spacing: 1px;
	font-weight: bold;
}
/* Scrollbar */ ::-webkit-scrollbar-thumb {
	background: #1aff1a !important;
	border-radius: 0;
}
::-webkit-scrollbar-track {
	background: #0a1a0a;
}

/* --- CYBERPUNK BASE --- */
:root {
  --cyber-pink: #ff00ff;
  --cyber-blue: #00ffff;
  --cyber-green: #00ff00;
}

/* --- KEYFRAMES --- */
@keyframes cyber-shift {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

@keyframes cyber-scan {
  0% { top: -10%; opacity: 0; }
  10% { opacity: 1; }
  90% { opacity: 1; }
  100% { top: 110%; opacity: 0; }
}

@keyframes glitch-text {
  0% { text-shadow: 1px 0 var(--cyber-pink), -1px 0 var(--cyber-blue); }
  50% { text-shadow: -1px 0 var(--cyber-pink), 1px 0 var(--cyber-blue); }
  100% { text-shadow: 1px 0 var(--cyber-pink), -1px 0 var(--cyber-blue); }
}

/* --- ANIMATED ELEMENTS --- */
#sidebar {
  position: relative;
  overflow: hidden;
  border-right: 1px solid rgba(255, 0, 255, 0.3) !important;
}

#sidebar::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  height: 3px;
  background: rgba(0, 255, 255, 0.6);
  box-shadow: 0 0 15px rgba(0, 255, 255, 1);
  animation: cyber-scan 3.5s linear infinite;
  pointer-events: none;
  z-index: 9999;
}

.user-message {
  background: linear-gradient(90deg, rgba(255, 0, 255, 0.05), rgba(0, 255, 255, 0.05), rgba(255, 0, 255, 0.05)) !important;
  background-size: 200% 200% !important;
  animation: cyber-shift 4s ease infinite !important;
  border: 1px solid rgba(0, 255, 255, 0.3) !important;
  box-shadow: 0 0 15px rgba(0, 255, 255, 0.1) !important;
}

h1 {
  animation: glitch-text 3s infinite !important;
}

/* Add a breathing glow to the send button */
button[type="submit"] {
  animation: cyber-shift 2s infinite !important;
  background: linear-gradient(90deg, var(--cyber-pink), var(--cyber-blue), var(--cyber-pink)) !important;
  background-size: 200% 200% !important;
  border: none !important;
  color: white !important;
}

:root {
  --primary-text: #8b1538;
  --primary-pink: #ff69b4;
  --primary-bg: #ffe0ec;
  --hover-bg: #ffc0db;
}

* {
  color: var(--primary-text) !important;
}

#send-message-button {
  background-color: var(--primary-pink) !important;
}

#sidebar {
  background-color: var(--primary-bg) !important;
}

#sidebar > div *:hover {
  background-color: var(--hover-bg) !important;
}

[aria-label="Voice mode"] {
  background-color: var(--primary-pink) !important;
}

.tippy-content {
  background-color: var(--primary-pink) !important;
  border-color: var(--primary-pink) !important;
}

.tippy-box {
  background-color: var(--primary-pink) !important;
  border-color: var(--primary-pink) !important;
}

button[type="submit"] {
  background-color: var(--primary-pink) !important;
}

[role="switch"][aria-checked="true"] {
  background-color: var(--primary-pink) !important;
}

