/* --- SOLAR FLARE LUXURY UI --- */
* {
	border-color: rgba(255, 180, 50, 0.15) !important;
}

/* Golden Prose */
.prose h1, .prose h2, .prose h3 {
	color: #ffcc00 !important;
	text-shadow: 0 0 10px rgba(255, 204, 0, 0.3);
	font-weight: 800 !important;
}
.prose code {
	color: #ffaa00 !important;
	background-color: rgba(255, 170, 0, 0.1) !important;
	border: 1px solid rgba(255, 170, 0, 0.3);
}

/* Obsidian Frosted Inputs */
input, textarea, .bg-gray-850 {
	background-color: rgba(18, 9, 2, 0.6) !important;
	backdrop-filter: blur(10px) !important;
	-webkit-backdrop-filter: blur(10px) !important;
	border: 1px solid rgba(255, 180, 50, 0.2) !important;
	border-radius: 12px !important;
	transition: all 0.3s ease;
}
input:focus, textarea:focus {
	border-color: #ffcc00 !important;
	box-shadow: 0 0 15px rgba(255, 204, 0, 0.15) !important;
}

/* Sunflare Gradient Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: linear-gradient(135deg, #ffcc00, #ff6600) !important;
	border: none !important;
	color: #26150a !important;
	font-weight: 700 !important;
	letter-spacing: 0.5px;
	box-shadow: 0 4px 15px rgba(255, 102, 0, 0.3);
	border-radius: 24px !important;
	transition: transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}
button.bg-blue-500:hover, button.bg-blue-600:hover {
	transform: translateY(-2px) scale(1.03);
	box-shadow: 0 8px 25px rgba(255, 102, 0, 0.5) !important;
}

/* Molten Scrollbar */
::-webkit-scrollbar-thumb {
	background: #ffaa00 !important;
	border: 3px solid transparent;
	background-clip: content-box;
	border-radius: 10px;
}
::-webkit-scrollbar-track {
	background: transparent !important;
}

/* ==============================
   Tactical HUD
   Designed to pair with the
   Tactical Liquid Grid canvas.
   ============================== */

/* --- Base: dark void + subtle grid --- */
body {
  background-color: #020a12 !important;
  background-image:
    linear-gradient(rgba(0, 220, 255, 0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0, 220, 255, 0.03) 1px, transparent 1px) !important;
  background-size: 40px 40px !important;
  background-attachment: fixed !important;
}

/* --- Transparency: let Canvas FX bleed through --- */
#app, #app > div, #app > div > div, main, .app,
[class*="bg-gray-"]:not(button):not(a):not(input):not(select):not(.user-message *) {
  background-color: transparent !important;
  background-image: none !important;
}

/* --- Sidebar: frosted glass panel --- */
#sidebar {
  background-color: rgba(2, 10, 18, 0.82) !important;
  backdrop-filter: blur(14px) saturate(1.2) !important;
  -webkit-backdrop-filter: blur(14px) saturate(1.2) !important;
  border-right: 1px solid rgba(0, 220, 255, 0.18) !important;
  box-shadow: inset -6px 0 20px rgba(0, 220, 255, 0.04) !important;
}

/* Sidebar gradient overlays */
.sidebar-bg-gradient-to-t,
.sidebar-bg-gradient-to-b {
  --tw-gradient-from: rgba(2, 10, 18, 0.9) !important;
  --tw-gradient-to: transparent !important;
}

/* Active sidebar chat highlight */
#sidebar a.bg-gray-100\/10,
#sidebar [class*="bg-gray-850"] {
  background-color: rgba(0, 220, 255, 0.08) !important;
  border-left: 2px solid #00dcff !important;
}

/* --- Navbar gradient overlay --- */
#navbar-bg-gradient-to-b {
  background-image: linear-gradient(
    to bottom,
    rgba(2, 10, 18, 0.8),
    transparent
  ) !important;
}

/* --- Chat scroll overlay --- */
#chat-container .bg-linear-to-t {
  background-image: linear-gradient(
    to top,
    rgba(2, 10, 18, 0.85),
    rgba(2, 10, 18, 0.3)
  ) !important;
}

/* --- User message bubble --- */
.user-message .rounded-3xl {
  background-color: rgba(0, 220, 255, 0.07) !important;
  border: 1px solid rgba(0, 220, 255, 0.15) !important;
}

/* --- Chat input area --- */
#chat-input-container {
  background-color: rgba(2, 10, 18, 0.7) !important;
  backdrop-filter: blur(10px) !important;
  -webkit-backdrop-filter: blur(10px) !important;
  border: 1px solid rgba(0, 220, 255, 0.15) !important;
  border-radius: 14px !important;
  transition: border-color 0.3s, box-shadow 0.3s !important;
}

#chat-input-container:focus-within {
  border-color: rgba(0, 220, 255, 0.5) !important;
  box-shadow: 0 0 20px rgba(0, 220, 255, 0.1),
              0 0 60px rgba(0, 220, 255, 0.04) !important;
}

textarea {
  background-color: transparent !important;
}

/* --- Send button: pulsing neon --- */
#send-message-button {
  background-color: rgba(0, 220, 255, 0.85) !important;
  color: #020a12 !important;
  box-shadow: 0 0 12px rgba(0, 220, 255, 0.35) !important;
  animation: hud-pulse 2.5s ease-in-out infinite !important;
}

@keyframes hud-pulse {
  0%, 100% { box-shadow: 0 0 8px rgba(0, 220, 255, 0.25); }
  50% { box-shadow: 0 0 22px rgba(0, 220, 255, 0.55),
                    0 0 50px rgba(0, 220, 255, 0.12); }
}

/* --- Prose / Markdown content --- */
.prose {
  color: #c4e8f0 !important;
}

.prose h1, .prose h2, .prose h3 {
  color: #00dcff !important;
}

.prose a {
  color: #00dcff !important;
  text-decoration-color: rgba(0, 220, 255, 0.3) !important;
}

.prose strong {
  color: #e0f4ff !important;
}

.prose hr {
  border-color: rgba(0, 220, 255, 0.12) !important;
}

/* --- Code blocks --- */
.prose pre {
  background-color: rgba(2, 8, 16, 0.92) !important;
  border: 1px solid rgba(0, 220, 255, 0.12) !important;
  border-radius: 10px !important;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4) !important;
}

.prose code:not(pre code) {
  background-color: rgba(0, 220, 255, 0.1) !important;
  color: #00dcff !important;
  padding: 1px 5px !important;
  border-radius: 4px !important;
}

/* --- Tables --- */
.prose table {
  border-color: rgba(0, 220, 255, 0.15) !important;
}

.prose th {
  background-color: rgba(0, 220, 255, 0.06) !important;
  color: #00dcff !important;
  border-color: rgba(0, 220, 255, 0.15) !important;
}

.prose td {
  border-color: rgba(0, 220, 255, 0.08) !important;
}

/* --- Inputs & textareas (settings, modals) --- */
input[type="text"],
input[type="password"],
input[type="email"],
input[type="number"],
input[type="search"],
select {
  background-color: rgba(2, 10, 18, 0.8) !important;
  border-color: rgba(0, 220, 255, 0.15) !important;
  color: #e0f4ff !important;
}

input:focus, select:focus {
  border-color: rgba(0, 220, 255, 0.4) !important;
  box-shadow: 0 0 10px rgba(0, 220, 255, 0.08) !important;
  outline: none !important;
}

/* --- Dialogs & modals --- */
[role="dialog"] > div {
  background-color: rgba(5, 14, 24, 0.95) !important;
  backdrop-filter: blur(16px) !important;
  border: 1px solid rgba(0, 220, 255, 0.12) !important;
}

/* --- Tooltips (Tippy) --- */
.tippy-box {
  background-color: rgba(2, 12, 20, 0.95) !important;
  border: 1px solid rgba(0, 220, 255, 0.2) !important;
  color: #c4e8f0 !important;
}

.tippy-arrow::before {
  color: rgba(2, 12, 20, 0.95) !important;
}

/* --- Global border tint --- */
* {
  border-color: rgba(0, 220, 255, 0.08) !important;
}

/* --- Scrollbar --- */
::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: rgba(0, 220, 255, 0.25);
  border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(0, 220, 255, 0.5);
}

/* --- Selection highlight --- */
::selection {
  background: rgba(0, 220, 255, 0.25) !important;
  color: #ffffff !important;
}

/* 1. CORE AESTHETIC: Blueprint Grid & Dark Background */
body {
    background-color: #020408 !important; /* Restored deep obsidian base */
    background-image: 
        linear-gradient(rgba(26, 177, 255, 0.04) 1px, transparent 1px), 
        linear-gradient(90deg, rgba(26, 177, 255, 0.04) 1px, transparent 1px) !important;
    background-size: 24px 24px !important;
    background-position: center top !important;
    font-family: 'JetBrains Mono', 'Monaco', monospace !important;
}

/* 2. SOFT BORDERS: Clean technical lines */
* {
    border-color: rgba(26, 177, 255, 0.15) !important;
}

/* 3. INPUTS & TEXT AREAS: Darkened with indigo tint */
input, textarea, .tiptap, .prose-editor, .bg-gray-50, .dark\:bg-gray-850 {
    background-color: rgba(10, 21, 32, 0.95) !important; /* Darker, more solid indigo */
    border: 1px solid rgba(26, 177, 255, 0.3) !important;
    color: #e6f7ff !important;
    border-radius: 8px !important;
}

/* 4. CHAT HISTORY: Clean, minimally intrusive separators */
.chat-user, .chat-assistant {
    background: transparent !important;
    border: none !important;
}

.user-message, .assistant-message {
    border-bottom: 1px solid rgba(26, 177, 255, 0.08) !important;
}

/* 5. SIDEBAR: Darker, blurred navigation */
#sidebar, .sidebar-container {
    background-color: rgba(2, 4, 8, 0.9) !important; /* Darkened sidebar */
    backdrop-filter: blur(12px);
    border-right: 1px solid rgba(26, 177, 255, 0.1) !important;
}

#sidebar-chat-item.bg-gray-100\/10, 
#sidebar-chat-item.bg-gray-850 {
    background-color: rgba(26, 177, 255, 0.12) !important;
    border-left: 2px solid #1ab1ff !important;
}

/* 6. MARKDOWN & CODE: Clean legibility */
.prose {
    color: #b3e6ff !important;
}

.prose pre {
    background-color: rgba(2, 4, 8, 0.95) !important;
    border: 1px solid rgba(26, 177, 255, 0.2) !important;
    border-radius: 8px !important;
}

.prose code:not(pre code) {
    background-color: rgba(26, 177, 255, 0.12) !important;
    color: #1ab1ff !important;
}

/* 7. ACCENT BUTTONS: Reverted to your bold high-contrast style */
button.bg-blue-500, button.bg-blue-600, .bg-blue-600 {
    background-color: #1ab1ff !important;
    border: 1px solid #e6f7ff !important;
    color: #020408 !important;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: bold;
    border-radius: 6px !important;
}

/* 8. SCROLLBAR & SELECTION */
::-webkit-scrollbar-thumb {
    background: rgba(26, 177, 255, 0.35) !important;
}

::selection {
    background: rgba(26, 177, 255, 0.3) !important;
    color: #ffffff !important;
}

/* Keep shadows hidden for that flat CAD drawing feel */
* {
    box-shadow: none !important;
}
